// Payload compatibility helpers for Copilot-like providers
// Adds sanitizer to remove reasoning-related fields for models that do not support them (e.g., gpt-5-mini)

export function isCopilotReasoningUnsupportedModel(modelId: string | undefined): boolean {
  if (!modelId) return false;
  const id = modelId.toLowerCase();
  // match known unsupported ids; extend list if needed
  return id.includes('gpt-5-mini') || id.includes('gpt-5-mini');
}

export function stripReasoningFields(params: any): any {
  if (!params || typeof params !== 'object') return params;
  const removeKeys = ['reasoning', 'reasoning_effort', 'reasoningEffort', 'enable_thinking', 'chat_template_kwargs'];
  for (const k of removeKeys) {
    if (k in params) delete params[k];
  }
  // nested reasoning object
  if ('reasoning' in params && typeof params.reasoning === 'object') {
    try { delete params.reasoning; } catch (e) { /* noop */ }
  }
  return params;
}

export function createCopilotPayloadCompatibilityWrapper(model: { id?: string } | string | undefined, params: any): any {
  const modelId = typeof model === 'string' ? model : model?.id;
  if (isCopilotReasoningUnsupportedModel(modelId)) {
    return stripReasoningFields(params);
  }
  return params;
}
